func HasTenantWith(preds ...predicate.Tenant) predicate.RetrievalChunk {
	return predicate.RetrievalChunk(func(s *sql.Selector) {
		step := newTenantStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.RetrievalChunk) predicate.RetrievalChunk {
	return predicate.RetrievalChunk(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.RetrievalChunk) predicate.RetrievalChunk {
	return predicate.RetrievalChunk(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.RetrievalChunk) predicate.RetrievalChunk {
	return predicate.RetrievalChunk(sql.NotPredicates(p))
}
